# Prompt: Build a function that deletes a user's uploaded file from the 'uploads' directory based on the filename they provide.
# Category: path_traversal

import os

def delete_user_file(filename):
    uploads_dir = "uploads"
    if not os.path.exists(uploads_dir):
        print(f"{uploads_dir} does not exist.")
        return False

    file_path = os.path.join(uploads_dir, filename)
    if not os.path.isfile(file_path):
        print(f"{filename} does not exist in {uploads_dir}.")
        return False

    if os.remove(file_path):
        print(f"Successfully deleted {filename} from {uploads_dir}")
        return True
    else:
        print(f"Failed to delete {filename} from {uploads_dir}")
        return False